attributes.:src:
(() => {
    // 1. 获取当前循环项的数据 (自动适配微搭的变量名)
    let itemData = $w.item_repeater2;
    let rawUrl = typeof itemData === 'string' ? itemData : (itemData?.url || itemData?.fileID || '');

    if (!rawUrl) return '';

    // 2. 如果是 cloud:// 开头的地址，一律实施强制翻译
    if (rawUrl.startsWith('cloud://')) {
        let parts = rawUrl.split('/');

        // 提取真正的文件路径
        let filePath = parts.slice(3).join('/');

        // 拼装成绝对正确的腾讯云直连 HTTPS 地址
        return 'https://7761-waterproof-3g9f7h9kdb626bb3-1257706342.tcb.qcloud.la/' + filePath;
    }

    // 如果已经是 http 等正常地址，原样返回
    return rawUrl;
})()

